const namespace = {
    Utils: {
        log: function(msg) { console.log(msg); },
        error: function(msg) { console.error(msg); }
    }
};
namespace.Utils.log('test');

class Namespace:
    class Utils:
        @staticmethod
        def log(msg):
            print(msg)
Namespace.Utils.log('test')

package com.utils.namespace;
public class Logger {
    public static void info(String msg) {
        System.out.println(msg);
    }
}

CREATE SCHEMA namespace_utils;
CREATE TABLE namespace_utils.logs (
    id INT, message VARCHAR(255)
);
